import React, { useState, useEffect } from "react";
import Logo from "./Logo";
import LoginForm from "./LoginForm";
import RegisterForm from "./RegisterForm";
import HomePage from "./HomePage"; // <- đây là file mới bạn vừa tạo

export default function App() {
  const [screen, setScreen] = useState("logo");

  useEffect(() => {
    if (screen === "logo") {
      const timer = setTimeout(() => setScreen("login"), 2000);
      return () => clearTimeout(timer);
    }
  }, [screen]);

  const handleLoginSuccess = () => {
    setScreen("home");
  };

  return (
    <div>
      {screen === "logo" && <Logo />}
      {screen === "login" && <LoginForm goToRegister={() => setScreen("register")} onLoginSuccess={handleLoginSuccess} />}
      {screen === "register" && <RegisterForm goToLogin={() => setScreen("login")} />}
      {screen === "home" && <HomePage />} {/* <- sẽ hiển thị trang HomePage với Sidebar và FriendList */}
    </div>
  );
}
